const HOMININS = [
  {id:'sahelanthropus',group:'proto',name:'Sahelanthropus tchadensis',short:'Sahelanthropus',icon:'🦴',color:'#8B5E3C',status:'extinct',mya:[7,6],brain:[320,380],height:'~120cm',weight:'~30–50kg',habitat:'Forested lake margin, Chad',tools:'None known',fire:'No',language:'None',sites:['Toros-Menalla, Chad'],desc:'The oldest known member of the human lineage — possibly. Discovered in Chad in 2001, dates to 6–7 million years ago, shortly after the human-chimp split. Its small canine teeth and possible bipedal posture suggest it belongs on the human side of the divide, but debate continues.',detail:'The skull was crushed flat and required meticulous 3D reconstruction. In 2022, a femur tentatively attributed to Sahelanthropus suggested it walked upright.',facts:[{l:'Lived',v:'~7–6 Mya'},{l:'Discovered',v:'2001, Chad'},{l:'Brain vol.',v:'~320–380 cm³'},{l:'Bipedal?',v:'Debated'}],tags:['Possible biped','Reduced canines','Human-chimp split era','Chad','Toumaï'],dna:{note:'Pre-DNA record'}},
  {id:'orrorin',group:'proto',name:'Orrorin tugenensis',short:'Orrorin',icon:'🦴',color:'#7a5530',status:'extinct',mya:[6.1,5.7],brain:[null,null],height:'~120cm',weight:'~35–50kg',habitat:'Mixed forest, Kenya',tools:'None known',fire:'No',language:'None',sites:['Tugen Hills, Kenya'],desc:'"Original Man" in Tugen. Represented mainly by femur bones showing clear adaptations for bipedal walking. Yet the hands show curved phalanges for tree-climbing, suggesting a dual lifestyle typical of early hominins.',detail:'The femoral morphology is strikingly similar to Australopithecus and even early Homo, causing some to propose Orrorin may be directly ancestral to Homo.',facts:[{l:'Lived',v:'~6.1–5.7 Mya'},{l:'Key fossil',v:'Femur (bipedal)'},{l:'Locomotion',v:'Biped + arboreal'}],tags:['Early biped','Thick enamel','Curved phalanges','Tugen Hills','Millennium Man'],dna:{note:'Pre-DNA record'}},
  {id:'ardipithecus_r',group:'proto',name:'Ardipithecus ramidus',short:'Ar. ramidus',icon:'🦴',color:'#a07050',status:'extinct',mya:[4.4,4.3],brain:[280,350],height:'~120cm',weight:'~50kg',habitat:'Woodland, Ethiopia',tools:'None known',fire:'No',language:'None',sites:['Aramis, Ethiopia'],desc:'"Ardi" — the 4.4-million-year-old near-complete skeleton rewrote our understanding of human origins. Ardipithecus ramidus walked upright but retained a grasping big toe for climbing. Crucially, it lacked the large canines of chimps, suggesting human social evolution began earlier than thought.',detail:'Ardi\'s foot combines an opposable big toe (ape-like) with rigid midfoot bones (bipedal). This mosaic suggests bipedalism did not evolve from a chimp-like ancestor.',facts:[{l:'Lived',v:'~4.4 Mya'},{l:'Discovered',v:'1994 (pub. 2009)'},{l:'Brain vol.',v:'~280–350 cm³'},{l:'Key fossil',v:'"Ardi" — near-complete'}],tags:['Mosaic anatomy','Opposable big toe','Woodland biped','Rewrote origins'],dna:{note:'Pre-DNA record'}},
  {id:'au_anamensis',group:'australopith',name:'Australopithecus anamensis',short:'Au. anamensis',icon:'🐒',color:'#b07840',status:'extinct',mya:[4.2,3.8],brain:[370,400],height:'~145cm',weight:'~45–55kg',habitat:'Lakeshore woodland, Kenya/Ethiopia',tools:'None known',fire:'No',language:'None',sites:['Kanapoi, Kenya','Woranso-Mille, Ethiopia'],desc:'The oldest definitive Australopithecus, bridging the gap between Ardipithecus and Au. afarensis. The tibia indicates habitual bipedalism. A 2019 discovery revealed a complete cranium with surprising ape-like features.',detail:'The 2019 Woranso-Mille cranium showed temporal overlap with afarensis — possibly two branches from a common ancestor.',facts:[{l:'Lived',v:'~4.2–3.8 Mya'},{l:'Discovered',v:'1994 (Leakey)'},{l:'Brain vol.',v:'~370–400 cm³'}],tags:['Oldest Australopithecus','Hard-food diet','Thick enamel','Transitional species'],dna:{note:'Pre-DNA record'}},
  {id:'au_afarensis',group:'australopith',name:'Australopithecus afarensis',short:'Au. afarensis',icon:'🚶',color:'#c08850',status:'extinct',mya:[3.9,2.9],brain:[380,450],height:'~105–150cm',weight:'~30–55kg',habitat:'Savanna and woodland, East Africa',tools:'Possible',fire:'No',language:'Calls, no speech',sites:['Hadar, Ethiopia','Laetoli, Tanzania','Dikika, Ethiopia'],desc:'"Lucy" (AL 288-1) — discovered in 1974 — is the most famous hominin fossil ever found. Walked fully upright (confirmed by the 3.6 Mya Laetoli footprints) but retained long, curved arms for tree climbing.',detail:'The Laetoli footprints in volcanic ash show two individuals walking upright with a gait nearly identical to modern humans — 3.6 million years ago.',facts:[{l:'Lived',v:'~3.9–2.9 Mya'},{l:'Famous fossil',v:'Lucy (AL 288-1)'},{l:'Brain vol.',v:'~380–450 cm³'},{l:'Key evidence',v:'Laetoli footprints'}],tags:['Lucy','Laetoli footprints','Savanna biped','Ancestral to Homo?'],dna:{note:'Pre-DNA record'}},
  {id:'au_africanus',group:'australopith',name:'Australopithecus africanus',short:'Au. africanus',icon:'🐒',color:'#b88050',status:'extinct',mya:[3.3,2.1],brain:[420,500],height:'~115–138cm',weight:'~30–45kg',habitat:'Mixed woodland-savanna, South Africa',tools:'Possible bone tools',fire:'No',language:'Limited',sites:['Taung, South Africa','Sterkfontein, South Africa'],desc:'The first australopith ever discovered. Raymond Dart\'s 1924 "Taung Child" was initially dismissed. Africanus has a rounder braincase and more human-like face than afarensis.',detail:'The Taung Child skull preserves a natural endocast — the first time paleoneurologists could study hominin brain morphology.',facts:[{l:'Lived',v:'~3.3–2.1 Mya'},{l:'Discovered',v:'1924 (Dart)'},{l:'Famous fossil',v:'Taung Child'}],tags:['Taung Child','First australopith','South Africa','Precision grip?'],dna:{note:'Pre-DNA record'}},
  {id:'par_boisei',group:'paranthropus',name:'Paranthropus boisei',short:'P. boisei',icon:'💪',color:'#9B3A3A',status:'extinct',mya:[2.4,1.4],brain:[410,530],height:'~124–137cm',weight:'~44–68kg',habitat:'Woodland-savanna edge, East Africa',tools:'None',fire:'No',language:'None',sites:['Olduvai Gorge, Tanzania','Koobi Fora, Kenya'],desc:'"Nutcracker Man" — Mary Leakey\'s 1959 discovery at Olduvai. With massive molars and a dramatic sagittal crest, boisei was spectacularly specialized for grinding tough plant foods. Coexisted with early Homo for over a million years.',detail:'Isotopic analysis surprisingly shows boisei ate mostly C4 grasses and sedges — not hard nuts as assumed. The dental machinery may have been an evolutionary safety net for fallback foods.',facts:[{l:'Lived',v:'~2.4–1.4 Mya'},{l:'Famous fossil',v:'OH 5 "Nutcracker Man"'},{l:'Brain vol.',v:'~410–530 cm³'},{l:'Molars',v:'Largest in any hominin'}],tags:['Nutcracker Man','Largest molars','C4 grass diet','Olduvai','Dead end lineage'],dna:{note:'Pre-DNA record'}},
  {id:'par_robustus',group:'paranthropus',name:'Paranthropus robustus',short:'P. robustus',icon:'💪',color:'#8B2A2A',status:'extinct',mya:[2.0,1.2],brain:[450,530],height:'~120–132cm',weight:'~40–54kg',habitat:'Woodland-savanna, South Africa',tools:'Possible bone digging tools',fire:'No',language:'None',sites:['Kromdraai','Swartkrans, South Africa'],desc:'The South African robust australopith — independently evolved its massive-jawed body plan. Possibly using bone tools for digging termite mounds. At Swartkrans, burned bones suggest possible fire use.',detail:'If robustus made fire, it would be the first non-Homo hominin to do so. Current consensus leans toward opportunistic use of natural fires, but debate persists.',facts:[{l:'Lived',v:'~2.0–1.2 Mya'},{l:'Tools?',v:'Bone digging tools'},{l:'Fire?',v:'Possible'}],tags:['South Africa','Bone tools?','Burned bones','Independent robust evolution'],dna:{note:'Pre-DNA record'}},
  {id:'h_habilis',group:'homo',name:'Homo habilis',short:'H. habilis',icon:'🪨',color:'#6B8B5E',status:'extinct',mya:[2.4,1.4],brain:[510,680],height:'~100–135cm',weight:'~32kg',habitat:'Woodland-savanna, East/South Africa',tools:'Oldowan (Mode 1)',fire:'No',language:'Proto-language possible',sites:['Olduvai Gorge','Koobi Fora, Kenya'],desc:'"Handy Man" — named by the Leakeys in 1964 for its association with Oldowan stone tools. H. habilis marks the conventional beginning of genus Homo. It had a larger brain than any australopith and a more human-like hand, but retained very long arms.',detail:'Recent evidence pushes tool use back to 3.3 Mya (Lomekwi 3), before habilis existed. This means either another species invented tools, or habilis was not the first toolmaker.',facts:[{l:'Lived',v:'~2.4–1.4 Mya'},{l:'Named',v:'1964 (Leakeys)'},{l:'Brain vol.',v:'~510–680 cm³'},{l:'Tools',v:'Oldowan (Mode 1)'}],tags:['Handy Man','Oldowan tools','First Homo?','Bushy Homo clade'],dna:{note:'Pre-DNA era'}},
  {id:'h_erectus',group:'homo',name:'Homo erectus',short:'H. erectus',icon:'🔥',color:'#8BAA7A',status:'extinct',mya:[1.89,0.11],brain:[600,1100],height:'~145–185cm',weight:'~40–68kg',habitat:'Savanna, forest, coast — worldwide',tools:'Acheulean (Mode 2)',fire:'Controlled use ~1 Mya',language:'Proto-language likely',sites:['Trinil, Java','Peking, China','Dmanisi, Georgia'],desc:'The great traveler — the first hominin to leave Africa, spreading across Asia and possibly Europe. With a body essentially modern in proportions, control of fire, and the sophisticated Acheulean hand axe, erectus persisted for nearly 2 million years.',detail:'The Nariokotome Boy (1984) — near-complete skeleton of a 1.5 Ma adolescent — revealed H. erectus had a fully modern body below the neck. Erectus in Java may have survived until 108,000 years ago, potentially overlapping with H. sapiens.',facts:[{l:'Lived',v:'~1.89 Mya – 110 Kya'},{l:'Range',v:'Africa, Asia, possibly Europe'},{l:'Brain vol.',v:'~600–1,100 cm³'},{l:'Fire',v:'Controlled ~1 Mya'}],tags:['First out of Africa','Fire control','Acheulean tools','Longest-lived Homo','Turkana Boy'],dna:{note:'No ancient DNA recovered'}},
  {id:'neanderthal',group:'homo',name:'Homo neanderthalensis',short:'Neanderthal',icon:'🏔️',color:'#7A9BAA',status:'extinct',mya:[0.4,0.04],brain:[1200,1750],height:'~164–168cm',weight:'~64–82kg',habitat:'Cold steppe, tundra, forest — Europe & W. Asia',tools:'Mousterian (Mode 3), personal ornaments',fire:'Routine',language:'Complex — FOXP2 gene',sites:['Neander Valley, Germany','Shanidar, Iraq','El Sidrón, Spain'],desc:'Our closest known extinct relative — and part of us. Neanderthals were cold-adapted hunters with brains on average slightly larger than ours, burying their dead, creating art and jewelry, and caring for the sick. All people outside sub-Saharan Africa carry ~1–4% Neanderthal DNA.',detail:'The Shanidar 1 individual survived multiple severe injuries requiring group care for years — evidence of Neanderthal compassion. Neanderthal cave art in Spain (65,000 years ago) predates H. sapiens arrival in Europe.',facts:[{l:'Lived',v:'~400–40 Kya'},{l:'Brain vol.',v:'~1,200–1,750 cm³'},{l:'DNA in us',v:'~1–4% (non-African)'},{l:'FOXP2',v:'Modern speech gene'}],tags:['1–4% in all non-Africans','Mousterian tools','Burial of dead','Cold adapted','FOXP2 speech gene'],dna:{neanderthal:100,denisovan:0,note:'~1–4% in all non-African modern humans'}},
  {id:'denisovans',group:'homo',name:'Denisovans',short:'Denisovans',icon:'🧬',color:'#7A8BAA',status:'extinct',mya:[0.4,0.03],brain:[null,null],height:null,weight:null,habitat:'Cave and open environments, Siberia and Asia',tools:'Advanced (beads, jewelry)',fire:'Yes',language:'Likely complex',sites:['Denisova Cave, Siberia','Baishiya Karst Cave, Tibet'],desc:'The ghost lineage given flesh. Discovered not from bones but from DNA — a 2010 analysis of a pinky bone from Denisova Cave revealed a previously unknown human species. Despite almost no fossil record, we know their genome in exquisite detail. Sister group of Neanderthals, diverging ~400 Kya.',detail:'Denisovan DNA lives in living people today: Melanesians and Aboriginal Australians carry ~3–5%. The EPAS1 gene enabling Tibetan altitude adaptation was inherited from Denisovans.',facts:[{l:'Lived',v:'~400–30 Kya'},{l:'Discovered',v:'2010 (via DNA)'},{l:'DNA in living people',v:'3–5% in Melanesians'},{l:'Key gift',v:'EPAS1 altitude gene'}],tags:['Ghost lineage','DNA discovery','Melanesian introgression','Denny hybrid','Tibet EPAS1'],dna:{neanderthal:0,denisovan:100,note:'3–5% in Melanesians/Papuans/Aboriginals'}},
  {id:'h_naledi',group:'homo',name:'Homo naledi',short:'H. naledi',icon:'⭐',color:'#AA9B7A',status:'extinct',mya:[0.335,0.236],brain:[465,610],height:'~143–150cm',weight:'~39–55kg',habitat:'Cave system, South Africa',tools:'Possible',fire:'Possible (cave torches?)',language:'Unknown',sites:['Rising Star Cave, South Africa'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/0/04/Homo_naledi_skull.jpg/320px-Homo_naledi_skull.jpg',imgCredit:'Lee Roger Berger research team, CC BY 4.0',desc:'The most astonishing paleoanthropological discovery of the 21st century. With a tiny australopith-sized brain (~500 cm³) yet modern-looking feet, wrists, and hands — and a geological age of only 236,000–335,000 years ago — naledi defies all expectations. It appears to have deliberately deposited its dead in a cave.',detail:'The 2022 discovery of possible fire use and engravings in the cave, if confirmed, would be revolutionary. Coexisting in South Africa with Homo sapiens at 250 Kya.',facts:[{l:'Lived',v:'~335–236 Kya'},{l:'Discovered',v:'2013 (Berger team)'},{l:'Brain vol.',v:'~465–610 cm³'},{l:'Behavior',v:'Possible deliberate burial'}],tags:['Rising Star Cave','Deliberate burial?','Mosaic anatomy','Tiny-brained late Homo'],dna:{note:'No DNA recovered from hot humid caves'}},
  {id:'h_floresiensis',group:'homo',name:'Homo floresiensis',short:'H. floresiensis',icon:'🌴',color:'#8B7050',status:'extinct',mya:[0.1,0.05],brain:[380,417],height:'~106cm',weight:'~25–30kg',habitat:'Tropical forest, Flores Island, Indonesia',tools:'Sophisticated stone tools',fire:'Possible',language:'Unknown',sites:['Liang Bua Cave, Flores, Indonesia'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Homo_floresiensis_cave.jpg/320px-Homo_floresiensis_cave.jpg',imgCredit:'Rosino, CC BY-SA 2.0',desc:'"The Hobbit." Discovered in 2003, had a brain the size of a grapefruit yet was associated with sophisticated stone tools. Island dwarfism likely explains the tiny body. Flores island folklore of the "Ebu Gogo" — small hairy people — may be a cultural memory of floresiensis.',detail:'May have survived until ~50,000 years ago — potentially coexisting with H. sapiens. Ancient DNA has not been recovered, leaving floresiensis\' exact ancestry unresolved.',facts:[{l:'Lived',v:'~100–50 Kya'},{l:'Brain vol.',v:'~380–417 cm³'},{l:'Height',v:'~106 cm'},{l:'Island',v:'Flores, Indonesia'}],tags:['The Hobbit','Island dwarfism','Tiny brain','Sophisticated tools','Ebu Gogo legend'],dna:{note:'No DNA recovered'}},
  {id:'au_bahrelghazali',group:'australopith',name:'Australopithecus bahrelghazali',short:'Au. bahrelghazali',icon:'🐒',color:'#a07040',status:'extinct',mya:[3.6,3.0],brain:[null,null],height:'~120cm',weight:'~30–40kg',habitat:'Savanna, Chad Basin',tools:'None known',fire:'No',language:'None',sites:['Bahr el Ghazal, Chad'],desc:'"Abel" - found in Chad in 1995, this species shattered the assumption that early australopiths lived only in East Africa. Its discovery in Chad, over 2,500 km west of the Rift Valley, suggests the hominin range in the Pliocene was far broader than previously imagined.',detail:'Abel consists mainly of a mandible fragment with teeth. The enamel structure and jaw morphology place it in Australopithecus, but its geographic isolation raises questions about migration routes across Plio-Pleistocene Africa.',facts:[{l:'Lived',v:'~3.6-3.0 Mya'},{l:'Discovered',v:'1995, Michel Brunet'},{l:'Region',v:'Chad, Central Africa'}],tags:['Abel','West Africa australopith','Shatters East Africa bias','Isolated mandible'],dna:{note:'Pre-DNA record'}},
  {id:'au_deyiremeda',group:'australopith',name:'Australopithecus deyiremeda',short:'Au. deyiremeda',icon:'🐒',color:'#b08048',status:'extinct',mya:[3.5,3.3],brain:[null,null],height:'~120cm',weight:'~30–45kg',habitat:'Woodland, Woranso-Mille, Ethiopia',tools:'None known',fire:'No',language:'None',sites:['Woranso-Mille, Ethiopia'],desc:'Named in 2015, Au. deyiremeda lived in the same region and at nearly the same time as Au. afarensis - overturning the notion that only one hominin existed per region per era. Its distinct jaw and tooth morphology identify it as a separate species coexisting with Lucy.',detail:'The coexistence of deyiremeda and afarensis in Woranso-Mille suggests the hominin family bush was genuinely bushy - multiple contemporaneous lineages competing or coexisting in the same habitat.',facts:[{l:'Lived',v:'~3.5-3.3 Mya'},{l:'Discovered',v:'2015 (Haile-Selassie)'},{l:'Key find',v:'Maxilla and mandible fragments'}],tags:['Contemporaneous with Lucy','Multi-species era','Woranso-Mille','New species 2015'],dna:{note:'Pre-DNA record'}},
  {id:'au_garhi',group:'australopith',name:'Australopithecus garhi',short:'Au. garhi',icon:'🐒',color:'#a87848',status:'extinct',mya:[2.5,2.5],brain:[450,null],height:'~130cm',weight:'~40–50kg',habitat:'Open savanna, Ethiopia',tools:'Associated with animal butchery',fire:'No',language:'None',sites:['Bouri, Ethiopia'],desc:'"Surprise" in the Afar language. Dated to 2.5 Mya - a critical transitional moment between Australopithecus and early Homo. Found with animal bones bearing cut marks, suggesting this species may have been butchering large mammals before H. habilis.',detail:'If garhi made stone tools, it would push the cognitive threshold for tool-use back into Australopithecus. The tools and hominin bones were found in the same deposit but not in direct association - the question remains open.',facts:[{l:'Lived',v:'~2.5 Mya'},{l:'Discovered',v:'1999 (Asfaw)'},{l:'Key association',v:'Cut-marked animal bones'}],tags:['Surprise species','Butchery evidence','2.5 Ma transition','Pre-Homo tools?'],dna:{note:'Pre-DNA record'}},
  {id:'au_sediba',group:'australopith',name:'Australopithecus sediba',short:'Au. sediba',icon:'🧗',color:'#a07850',status:'extinct',mya:[1.98,1.78],brain:[420,440],height:'~130cm',weight:'~27–33kg',habitat:'Woodland, South Africa',tools:'None confirmed',fire:'No',language:'None',sites:['Malapa, South Africa'],desc:'Discovered in 2010 - an extraordinary mosaic. Au. sediba has a small australopith brain but hands capable of precision gripping, and a Homo-like pelvis ideal for upright walking. Some researchers argue it may be ancestral to Homo; others see it as a parallel South African evolutionary experiment.',detail:'The Malapa site preserved two articulated skeletons - an adult female and juvenile male - with soft tissue impressions. One of the most complete early hominin specimens known.',facts:[{l:'Lived',v:'~1.98-1.78 Mya'},{l:'Discovered',v:'2010 (Berger)'},{l:'Brain vol.',v:'~420-440 cm3'},{l:'Key fossil',v:'Two near-complete skeletons'}],tags:['Precision grip','Homo-like pelvis','Malapa death trap','Homo ancestor?','2010 discovery'],dna:{note:'Pre-DNA record'}},
  {id:'au_prometheus',group:'australopith',name:'Australopithecus prometheus',short:'Au. prometheus (Little Foot)',icon:'🦶',color:'#b08858',status:'extinct',mya:[3.67,3.67],brain:[408,null],height:'~135cm',weight:'~40–50kg',habitat:'Cave and forest margin, South Africa',tools:'None',fire:'No',language:'None',sites:['Sterkfontein, South Africa'],desc:'"Little Foot" - a near-complete skeleton (StW 573) excavated over 20 years from Sterkfontein cave. Dated controversially to 3.67 Mya, which would make it older than Lucy. The long arms and grasping big toe show strong arboreal adaptations alongside bipedalism.',detail:'Whether Little Foot represents a distinct species or falls within africanus is actively debated. The 20-year excavation by Ron Clarke required removing the skeleton from cave breccia with dental picks - one of paleontology great feats of patience.',facts:[{l:'Lived',v:'~3.67 Mya (debated)'},{l:'Discovered',v:'1994-2017 excavation'},{l:'Brain vol.',v:'~408 cm3'},{l:'Status',v:'Species debated'}],tags:['Little Foot','StW 573','3.67 Ma?','20-year excavation','Sterkfontein','Arboreal biped'],dna:{note:'Pre-DNA record'}},
  {id:'kenyanthropus',group:'proto',name:'Kenyanthropus platyops',short:'Kenyanthropus',icon:'🦴',color:'#907050',status:'extinct',mya:[3.5,3.2],brain:[null,null],height:'~130cm',weight:'~40kg',habitat:'Mixed woodland-lakeside, Kenya',tools:'None known',fire:'No',language:'None',sites:['Lomekwi, Lake Turkana, Kenya'],desc:'"Flat-faced man of Kenya." Discovered by Meave Leakey in 1999 at Lake Turkana. This 3.5-million-year-old skull has a remarkably flat face unlike any australopith - more resembling Homo than the projecting faces of Australopithecus. Its existence challenges the neat Lucy-to-Homo narrative.',detail:'Some researchers argue Kenyanthropus, not afarensis, could be ancestral to Homo. If so, Au. afarensis was a parallel branch - and the ancestor of all humans lived at Turkana, not Hadar.',facts:[{l:'Lived',v:'~3.5-3.2 Mya'},{l:'Discovered',v:'1999 (M. Leakey)'},{l:'Key feature',v:'Extremely flat face'}],tags:['Flat-faced','Challenges Lucy ancestry','Lake Turkana','Possible Homo ancestor'],dna:{note:'Pre-DNA record'}},
  {id:'par_aethiopicus',group:'paranthropus',name:'Paranthropus aethiopicus',short:'P. aethiopicus',icon:'💪',color:'#7A2A2A',status:'extinct',mya:[2.7,2.3],brain:[410,null],height:'~125cm',weight:'~44kg',habitat:'Lakeshore savanna, East Africa',tools:'None',fire:'No',language:'None',sites:['Omo River, Ethiopia','West Turkana, Kenya'],desc:'The earliest and most primitive Paranthropus. The Black Skull (KNM-WT 17000, 1985) is its defining specimen - dramatically black from manganese mineralization. It has the largest sagittal crest of any hominin and extremely prognathic lower face.',detail:'The Black Skull structure suggests the robust skull architecture evolved independently from africanus, implying Paranthropus may have evolved twice in parallel.',facts:[{l:'Lived',v:'~2.7-2.3 Mya'},{l:'Key fossil',v:'Black Skull (1985)'},{l:'Brain vol.',v:'~410 cm3'},{l:'Crest',v:'Largest sagittal crest known'}],tags:['Black Skull','Largest sagittal crest','Earliest Paranthropus','Polyphyletic origin?'],dna:{note:'Pre-DNA record'}},
  {id:'h_rudolfensis',group:'homo',name:'Homo rudolfensis',short:'H. rudolfensis',icon:'🪨',color:'#6A7B50',status:'extinct',mya:[2.4,1.8],brain:[700,800],height:'~150cm',weight:'~45kg',habitat:'Woodland-savanna, East Africa',tools:'Oldowan possible',fire:'No',language:'Rudimentary',sites:['Koobi Fora, Kenya'],desc:'Known from a single large skull (KNM-ER 1470) with a notably flat, broad face and large braincase. Its relationship to H. habilis is intensely debated - some see them as one variable species; others as two coexisting Homo lineages, demonstrating that early genus Homo was immediately diverse.',detail:'The 1470 skull was assembled from hundreds of fragments. Initial dating suggested 2.9 Mya. Later recalibration placed it at ~1.9 Mya, resolving a major conflict with evolutionary theory.',facts:[{l:'Lived',v:'~2.4-1.8 Mya'},{l:'Key fossil',v:'KNM-ER 1470'},{l:'Brain vol.',v:'~700-800 cm3'},{l:'Debate',v:'Same species as habilis?'}],tags:['KNM-ER 1470','Large flat face','Debated species','Early Homo diversity'],dna:{note:'Pre-DNA era'}},
  {id:'h_antecessor',group:'homo',name:'Homo antecessor',short:'H. antecessor',icon:'⚒️',color:'#7A8A6A',status:'extinct',mya:[1.2,0.8],brain:[1000,1100],height:'~170cm',weight:'~60–90kg',habitat:'Forest-savanna, Spain',tools:'Acheulean',fire:'Possible',language:'Proto-language',sites:['Atapuerca, Spain'],desc:'The oldest western European hominin, discovered at Atapuerca cave in 1994. H. antecessor may represent the common ancestor of both Neanderthals and Homo sapiens. Includes evidence of cannibalism - defleshing marks on juvenile bones at Gran Dolina.',detail:'The face of antecessor is strikingly modern, leading Bermudez de Castro to propose it as pioneer man who colonized Europe from Africa and gave rise to the Neanderthal lineage.',facts:[{l:'Lived',v:'~1.2-0.8 Mya'},{l:'Discovered',v:'1994, Atapuerca'},{l:'Brain vol.',v:'~1,000-1,100 cm3'},{l:'Evidence',v:'Cannibalism at Atapuerca'}],tags:['Pioneer Man','Atapuerca','Earliest W. European','Cannibalism evidence','Common ancestor?'],dna:{note:'Ancient protein analysis links to Neanderthal lineage'}},
  {id:'h_heidelbergensis',group:'homo',name:'Homo heidelbergensis',short:'H. heidelbergensis',icon:'⚒️',color:'#809070',status:'extinct',mya:[0.7,0.2],brain:[1100,1400],height:'~175cm',weight:'~60–80kg',habitat:'Forest, savanna, tundra - Africa and Europe',tools:'Advanced Acheulean, wooden spears',fire:'Routine',language:'Proto-language, likely advanced',sites:['Mauer, Germany','Bodo, Ethiopia'],desc:'A cosmopolitan hominin spanning Africa and Europe. The probable ancestor of Neanderthals in Europe and Homo sapiens in Africa. Notable for the Schoningen spears (400,000 years old) - the oldest complete hunting weapons ever found - indicating sophisticated planned hunting of wild horses.',detail:'Heidelbergensis represents the threshold where symbolic thought becomes plausible. Cave lion skulls show strategic use of topography to herd and ambush mega-fauna.',facts:[{l:'Lived',v:'~700-200 Kya'},{l:'Range',v:'Africa + Europe'},{l:'Brain vol.',v:'~1,100-1,400 cm3'},{l:'Key find',v:'Schoningen wooden spears'}],tags:['Schoningen spears','Neanderthal ancestor','Sapiens ancestor?','Strategic hunters','Both Africa & Europe'],dna:{note:'No DNA; protein analysis groups with Neanderthal clade'}},
  {id:'h_bodoensis',group:'homo',name:'Homo bodoensis',short:'H. bodoensis',icon:'⚒️',color:'#7A9060',status:'extinct',mya:[0.6,0.15],brain:[1250,null],height:'~175cm',weight:'~65kg',habitat:'Savanna and woodland, Africa',tools:'Acheulean',fire:'Yes',language:'Advanced proto-language',sites:['Bodo D\'ar, Ethiopia'],desc:'Described as a new species in 2021 to resolve confusion about African Middle Pleistocene hominins. H. bodoensis is proposed as the direct African ancestor of H. sapiens. Named for the Bodo skull which shows cut marks indicating deliberate defleshing.',detail:'The 2021 description by Roksandic et al. argues H. heidelbergensis should be restricted to Europe, and that the African Middle Pleistocene lineage deserves its own designation as our direct ancestors.',facts:[{l:'Lived',v:'~600-150 Kya'},{l:'Described',v:'2021 (Roksandic et al.)'},{l:'Brain vol.',v:'~1,250 cm3'},{l:'Key fossil',v:'Bodo skull'}],tags:['New species 2021','Sapiens direct ancestor?','African MPA','Bodo skull','Defleshing marks'],dna:{note:'No DNA; proposed direct sapiens ancestor'}},
  {id:'h_luzonensis',group:'homo',name:'Homo luzonensis',short:'H. luzonensis',icon:'🏝️',color:'#7A6B50',status:'extinct',mya:[0.067,0.05],brain:[null,null],height:'~120cm',weight:'~25kg',habitat:'Tropical island, Luzon, Philippines',tools:'Stone tools',fire:'Unknown',language:'Unknown',sites:['Callao Cave, Luzon, Philippines'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Callao_Cave_Entrance.jpg/320px-Callao_Cave_Entrance.jpg',imgCredit:'Judgefloro, CC BY-SA 4.0',desc:'Announced in 2019 from Callao Cave - a tiny island hominin with a mosaic of features. Some foot and finger bones resemble Australopithecus rather than any Homo. With an age of 50-67 thousand years ago, it coexisted with Denisovans, H. sapiens, and floresiensis - the most crowded moment in hominin history.',detail:'The survival of primitive morphology in luzonensis may reflect island dwarfism or indicate an earlier migration to Southeast Asia than previously recognized.',facts:[{l:'Lived',v:'~67-50 Kya'},{l:'Announced',v:'2019'},{l:'Region',v:'Callao Cave, Luzon'},{l:'Features',v:'Mosaic Australopithecus + Homo'}],tags:['New species 2019','Philippine hominin','Mosaic anatomy','Island dwarf','Callao Cave'],dna:{note:'No DNA recovered from tropical site'}},
  {id:'h_longi',group:'homo',name:'Homo longi',short:'H. longi (Dragon Man)',icon:'🐉',color:'#7A8090',status:'extinct',mya:[0.146,0.146],brain:[1420,null],height:'~180cm',weight:'~70kg',habitat:'Cold temperate Asia',tools:'Unknown',fire:'Possible',language:'Possible',sites:['Harbin, Heilongjiang, China'],desc:'"Dragon Man" - a massive skull found in Harbin, China, with a brain size matching Homo sapiens but archaic features. Described in 2021, it may be more closely related to H. sapiens than Neanderthals are - which would fundamentally reorganize the human family tree.',detail:'The Harbin skull was allegedly discovered in the 1930s, hidden in a well for 80+ years, and donated to researchers before the original discoverer death. Protein analysis supports placement near the sapiens lineage.',facts:[{l:'Lived',v:'~146 Kya'},{l:'Brain vol.',v:'~1,420 cm3'},{l:'Described',v:'2021'},{l:'Claim',v:'Closer to sapiens than Neanderthal'}],tags:['Dragon Man','Harbin skull','New species 2021','Paleoproteomics','Reorganizes family tree'],dna:{note:'No DNA; protein analysis places near sapiens lineage'}},
  {id:'h_sapiens',group:'homo',name:'Homo sapiens',short:'H. sapiens',icon:'🧠',color:'#E8B86D',status:'surviving',mya:[0.3,0],brain:[1350,1500],height:'~170cm avg',weight:'~62–80kg',habitat:'Universal — all continents',tools:'All technology in history',fire:'Total control',language:'Full language',sites:['Jebel Irhoud, Morocco','Omo Kibish, Ethiopia'],desc:'You. Emerged ~300,000 years ago in Africa. Behavioral modernity appeared ~70,000–50,000 years ago. We left Africa in multiple waves, interbreeding with Neanderthals, Denisovans, and possibly other archaic humans. We carry a mosaic of archaic DNA in our genomes today.',detail:'In 300,000 years we reshaped the biosphere, triggered a mass extinction, split the atom, walked on the moon, and began sequencing the genomes of every organism on this tree of life.',facts:[{l:'Appeared',v:'~300 Kya (Africa)'},{l:'Population',v:'~8.1 billion'},{l:'Brain vol.',v:'~1,350–1,500 cm³'},{l:'Neanderthal DNA',v:'~1–4% (non-African)'}],tags:['Language & art','Global dispersal','Archaic DNA legacy','Agriculture ~12 Kya','Space travel','FOXP2'],dna:{neanderthal:2,denisovan:1,note:'~1–4% Neanderthal + up to 5% Denisovan in some populations'}},
  {id:'homo-naledi',group:'Homo',name:'Homo naledi',short:'The Cave Puzzler',icon:'🧑',color:'#9a7055',status:'extinct',mya:[0.335,0.236],brain:[465,610],height:'~144cm',weight:'~40kg',habitat:'Cave systems, South Africa',tools:'Possible fire use',fire:'Possible',language:'Unknown',sites:['Rising Star Cave, South Africa'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/Homo_naledi_skull.jpg/320px-Homo_naledi_skull.jpg',imgCredit:'Lee Roger Berger research team, CC BY 4.0',desc:'Discovered in 2013 deep inside a nearly inaccessible cave system in South Africa. Has a baffling mix of primitive and modern features — small brain but human-like hands and feet.',detail:'Homo naledi may have deliberately disposed of their dead in these caves — which would be the earliest known mortuary behavior, previously thought uniquely human. The caves required squeezing through gaps as narrow as 17cm to access.',funFact:'Homo naledi apparently buried their dead in pitch-black caves requiring expert climbing through 17cm gaps — with a brain one third the size of ours.',facts:[{l:'Brain size',v:'465–610 cc'},{l:'Discovery',v:'2013, Rising Star Cave'},{l:'Access',v:'17cm gap to reach'}],tags:['Cave burial','Small brain','Mixed features'],dna:{haplogroup:'Unknown',neanderthal:'Unknown',denisovan:'Unknown'}},
  {id:'homo-floresiensis',group:'Homo',name:'Homo floresiensis',short:'The Hobbit',icon:'🧑',color:'#9a7055',status:'extinct',mya:[0.1,0.05],brain:[380,380],height:'~106cm',weight:'~25kg',habitat:'Tropical island forest, Flores',tools:'Stone tools',fire:'Evidence found',language:'Unknown',sites:['Liang Bua Cave, Flores, Indonesia'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c3/Homo_floresiensis_cave.jpg/320px-Homo_floresiensis_cave.jpg',imgCredit:'Rosino, CC BY-SA 2.0',desc:'A tiny human species standing just 1 meter tall that survived on the island of Flores until 50,000 years ago — possibly overlapping with modern humans. Nicknamed "The Hobbit."',detail:'Floresiensis used fire and made sophisticated stone tools despite a brain smaller than a chimpanzee\'s. Island dwarfism — the same process that shrinks elephants on islands — likely reduced their size from Homo erectus ancestors.',funFact:'Homo floresiensis stood 1 meter tall, had a brain smaller than a chimp, yet made sophisticated tools and used fire — possibly alive at the same time as modern humans just 50,000 years ago.',facts:[{l:'Height',v:'~1 meter'},{l:'Brain',v:'380 cc (smaller than chimp)'},{l:'Survived until',v:'~50,000 years ago'}],tags:['Island dwarfism','Hobbit','Tool use'],dna:{haplogroup:'Unknown',neanderthal:'Unknown',denisovan:'Unknown'}},
  {id:'denisovan',group:'Archaic Homo',name:'Denisovans',short:'The Ghost Lineage',icon:'👤',color:'#7a6a55',status:'extinct',mya:[0.5,0.03],brain:[1200,1400],height:'Unknown',weight:'Unknown',habitat:'Asia — Siberia to Southeast Asia',tools:'Advanced stone and bone tools',fire:'Yes',language:'Possible',sites:['Denisova Cave, Siberia','Xiahe, Tibet','Tam Ngu Hao, Laos'],img:'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Denisova_Cave_main_gallery.jpg/320px-Denisova_Cave_main_gallery.jpg',imgCredit:'Демин Алексей Барнаул, CC BY-SA 3.0',desc:'Known almost entirely from DNA — only a finger bone, teeth, and jaw have been found. Yet their genome has been fully sequenced. Up to 6% of modern Melanesian DNA is Denisovan.',detail:'Denisovans interbred with modern humans in Asia. The gene variant allowing Tibetans to live at high altitude — EPAS1 — comes from Denisovans. They may have ranged from Siberia to Southeast Asia.',funFact:'We know an entire human species from a single finger bone — yet their DNA lives on in millions of people today, and gave Tibetans the gene allowing them to breathe at high altitude.',facts:[{l:'Known fossils',v:'Finger bone, teeth, jaw'},{l:'DNA in modern humans',v:'Up to 6% in Melanesians'},{l:'Gift to Tibetans',v:'High-altitude breathing gene'}],tags:['Ghost lineage','DNA only','Interbreeding'],dna:{haplogroup:'Unknown',neanderthal:'Interbred',denisovan:'100%'}}
];

